public class Car {
    String brand;
    int year;

    public Car(String brand, int year) {
        this.brand = brand;
        this.year = year;
    }

    public String describe() {
        return brand + " (" + year + ")";
    }
}

// Usage
Car car = new Car("Toyota", 2022);
System.out.println(car.describe()); // Toyota (2022)

public class Animal {
    public String speak() {
        return "...";
    }
}

public class Dog extends Animal {
    @Override
    public String speak() {
        return "Woof!";
    }
}

Animal a = new Dog();
System.out.println(a.speak()); // Woof!

